const item = $input.first().json;
const design = item.design;
const width = design.thumbnail.width;
const height = design.thumbnail.height;
const ratio = width / height;

// Post (400x500)   → ratio ~0.80
// Stories (335x596) → ratio ~0.56
// Carousel (1080x1440) → ratio ~0.75 — entre post y square
// Umbral: < 0.62 = stories | 0.62-0.78 = carousel | > 0.78 = post

let format;
if (ratio < 0.62) {
  format = 'stories';
} else if (ratio <= 0.78) {
  format = 'carousel';
} else {
  format = 'post';
}

return [{ json: {
  Design_ID: design.id,
  format: format,
  ratio: ratio
}}];

